import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

function getWeatherEmoji(condition: string): string {
  const lowerCondition = condition.toLowerCase();

  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
  if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('thunder') || lowerCondition.includes('storm')) return '⛈️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';

  return '🌤️'; // Default
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City Name */}
        <Stack direction="vertical" gap={8}>
          <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
            {city}
          </Text>
        </Stack>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={32} align="center" justify="between">
          <Stack direction="vertical" gap={8} align="start">
            {/* Temperature - Large and Prominent */}
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                lineHeight: 1,
              }}
            >
              {temperature}°{unit}
            </div>

            {/* Condition with Emoji */}
            <Stack direction="horizontal" gap={8} align="center">
              <span style={{ fontSize: '32px' }}>{weatherEmoji}</span>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="semibold"
              >
                {condition}
              </Text>
            </Stack>
          </Stack>

          {/* Weather Details - Humidity & Wind */}
          <Stack direction="vertical" gap={16}>
            <Box
              padding={16}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-neutral-50, #f9fafb)"
              style={{
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              }}
            >
              <Stack direction="vertical" gap={12}>
                {/* Humidity */}
                <Row gap={8} align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                    weight="medium"
                  >
                    Humidity
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="semibold"
                  >
                    {humidity}%
                  </Text>
                </Row>

                {/* Wind Speed */}
                <Row gap={8} align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                    weight="medium"
                  >
                    Wind
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="semibold"
                  >
                    {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
                  </Text>
                </Row>
              </Stack>
            </Box>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row
            gap={12}
            align="stretch"
            justify="start"
            wrap={false}
            style={{
              overflowX: 'auto',
              paddingBottom: 8,
            }}
          >
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-neutral-50, #f9fafb)"
                style={{
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                  minWidth: '100px',
                  textAlign: 'center',
                  flex: '0 0 auto',
                }}
              >
                <Stack direction="vertical" gap={8} align="center" justify="center">
                  {/* Day Name */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                  >
                    {day.day}
                  </Text>

                  {/* Weather Icon/Emoji */}
                  <div style={{ fontSize: '24px' }}>
                    {day.icon}
                  </div>

                  {/* High Temp */}
                  <Text
                    variant="body"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    weight="semibold"
                  >
                    {day.high}°
                  </Text>

                  {/* Low Temp */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                  >
                    {day.low}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
